configuration.jsScript:
/* get the deviceList and 
the attributes of the message */
var averageList = msg.params.timeseriesAverage;
delete msg.method;
delete msg.params;

/* variable declaration for 
the counting of the average */
var sumTemperature = 0, sumWeight = 0, sumHumidity = 0, sumNoise = 0;
var temperatureCounter = 0, weightCounter = 0, humidityCounter = 0, noiseCounter = 0;

for(const singleAverage of averageList){
    /* if it's the measure of another device add it to 
    the sum so as to do the average later */
    if(singleAverage.key === "average_temperature" && singleAverage.deviceName!=metadata.deviceName){
        sumTemperature += singleAverage.value;
        temperatureCounter++;
    }
    /* if it's the value of the device 
    add it to the message directly */
    else if(singleAverage.key === "average_temperature")
        msg.device_temperature = singleAverage.value;
    /* do the rest for the other averages types */
    else if(singleAverage.key === "average_humidity" && singleAverage.deviceName!=metadata.deviceName){
        sumHumidity += singleAverage.value;
        humidityCounter++;
    }
    else if(singleAverage.key === "average_humidity")
        msg.device_humidity = singleAverage.value;
    else if(singleAverage.key === "average_weight" && singleAverage.deviceName!=metadata.deviceName){
        sumWeight += singleAverage.value;
        weightCounter++;
    }
    else if(singleAverage.key === "average_weight")
        msg.device_weight = singleAverage.value;
    else if(singleAverage.key === "average_noise" && singleAverage.deviceName!=metadata.deviceName){
        sumNoise += singleAverage.value;
        noiseCounter++;
    }
    else if(singleAverage.key === "average_noise")
        msg.device_noise = singleAverage.value;
}

/* finally calculate the averages of the
measures checking if it has some values to gather */
if(temperatureCounter != 0)
    msg.other_temperature = sumTemperature / temperatureCounter;

if(humidityCounter != 0)
    msg.other_humidity = sumHumidity / humidityCounter;

if(weightCounter != 0)
    msg.other_weight = sumWeight / weightCounter;

if(noiseCounter != 0)
    msg.other_noise = sumNoise / noiseCounter;

/* then check if there is both 
average of the single measure and average of other devices 
in order to make a general_average */
if('device_temperature' in msg && 'other_temperature' in msg)
    msg.general_temperature = (sumTemperature + msg.device_temperature) / (temperatureCounter+1);
if('device_humidity' in msg && 'other_humidity' in msg)
    msg.general_humidity = (sumHumidity + msg.device_humidity) / (humidityCounter+1);
if('device_weight' in msg && 'other_weight' in msg)
    msg.general_weight = (sumWeight + msg.device_weight) / (weightCounter+1);
if('device_noise' in msg && 'other_noise' in msg)
    msg.general_noise = (sumNoise + msg.device_noise) / (noiseCounter+1);

return {msg: msg, metadata: metadata, msgType: msgType};

/* define constants as thresholds
for measures tolerance */
const DIFFERENCETEMPERATURE_THRESHOLD =
    5; // difference of temperature in °C
const DIFFERENCEWEIGHT_THRESHOLD =
    3; // difference of weight in kg 
const DIFFERENCEHUMIDITY_THRESHOLD =
    20; // difference of humidity in %
const DIFFERENCENOISE_THRESHOLD =
    0.20; // relative difference of noise between the measures

/* define variables and lists for the execution
of the script */
var errors = [];

/* do the controls and check if the averages
are too different between them. 
In that case add an error */
if ('device_temperature' in msg && 'other_temperature' in
    msg && Math.abs(msg.device_temperature - msg
        .other_temperature) >=
    DIFFERENCETEMPERATURE_THRESHOLD)
    errors.push("different_temperature");
if ('device_humidity' in msg && 'other_humidity' in msg &&
    Math.abs(msg.device_humidity - msg.other_humidity) >=
    DIFFERENCEHUMIDITY_THRESHOLD)
    errors.push("different_humidity");
if ('device_weight' in msg && 'other_weight' in
    msg && Math.abs(msg.device_weight - msg
        .other_weight) >= DIFFERENCEWEIGHT_THRESHOLD)
    errors.push("different_weight");
if ('device_noise' in msg && 'other_noise' in
    msg && Math.abs(1 - msg.device_noise / msg
        .other_noise) >= DIFFERENCENOISE_THRESHOLD)
    errors.push("different_noise");

/* if no error has been added,
return an ok condition */
if(errors.length === 0)
    errors.push("ok");

return errors;

