/* delete all the keys that are not essential 
to be posted in the attributes of the asset */
for(const singleKey of Object.keys(msg)){
    if(!singleKey.startsWith("general_"))
        delete msg[singleKey];
}

return {msg: msg, metadata: metadata, msgType: "POST_ATTRIBUTES_REQUEST"};

